import { writeFile } from "fs/promises";
import path from "path";
import { PDFDocument } from "pdf-lib";
import Tesseract from "tesseract.js";

const uploadDir = path.join(process.cwd(), "public/uploads");

export async function POST(req: Request) {
  try {
    const formData = await req.formData();
    const file = formData.get("file") as File;

    if (!file) {
      return new Response(JSON.stringify({ error: "No file uploaded" }), {
        status: 400,
      });
    }

    const filePath = path.join(uploadDir, file.name);
    const arrayBuffer = await file.arrayBuffer();
    await writeFile(filePath, Buffer.from(arrayBuffer));

    // Read PDF and extract images
    const pdfBytes = Buffer.from(arrayBuffer);
    const pdfDoc = await PDFDocument.load(pdfBytes);
    const pages = pdfDoc.getPages();
    const firstPage = pages[0];

    const images = firstPage.node.getImages();
    if (images.length === 0) {
      return new Response(
        JSON.stringify({ error: "No images found in the PDF" }),
        { status: 400 }
      );
    }

    const image = images[0];
    const imageBytes = await image.imageBytes;
    const imagePath = path.join(uploadDir, "extracted_image.png");
    await writeFile(imagePath, imageBytes);

    // Perform OCR
    const {
      data: { text },
    } = await Tesseract.recognize(imagePath, "eng");

    return new Response(JSON.stringify({ text }), { status: 200 });
  } catch (error) {
    return new Response(JSON.stringify({ error: error.message }), {
      status: 500,
    });
  }
}
